 322→const isPrivateIpv4Address = (ip) => {
 323→    const parts = ip.split('.').map((part) => Number(part));
 324→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
 325→        return true;
 326→    }
 327→
 328→    const [a, b] = parts;
 329→    if (a === 10 || a === 127 || a === 0) return true;
 330→    if (a === 169 && b === 254) return true;
 331→    if (a === 172 && b >= 16 && b <= 31) return true;
 332→    if (a === 192 && b === 168) return true;
 333→    return false;
 334→};
