 336→const isPrivateIpv6Address = (ip) => {
 337→    const normalized = ip.toLowerCase();
 338→    return (
 339→        normalized === '::1' ||
 340→        normalized.startsWith('fc') ||
 341→        normalized.startsWith('fd') ||
 342→        normalized.startsWith('fe80:')
 343→    );
 344→};
