 357→            return false;
 358→        }
 359→
 360→        const hostname = parsed.hostname.toLowerCase();
 361→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
 362→            return false;
 363→        }
 364→
 365→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
 366→            return false;
