 420→const fetchRemoteImageBuffer = async (imageUrl) => {
 421→    const controller = new AbortController();
 422→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
 423→
 424→    try {
 425→        const response = await fetch(imageUrl, {
 426→            method: 'GET',
 427→            redirect: 'follow',
 428→            signal: controller.signal,
 429→            headers: {
 430→                Accept: 'image/*,*/*;q=0.8',
 431→                'Accept-Encoding': 'identity',
 432→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
 433→            },
 434→        });
 435→
 436→        if (!response.ok) {
 437→            throw new Error(`upstream image status ${response.status}`);
 438→        }
 439→
 440→        const finalUrl = response.url || imageUrl;
 441→        if (!isSafeRemoteImageUrl(finalUrl)) {
 442→            throw new Error('upstream redirected to unsafe url');
 443→        }
 444→
 445→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
 446→        if (!contentType.startsWith('image/')) {
 447→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
 448→        }
 449→        if (contentType.includes('image/svg')) {
 450→            throw new Error('svg images are not used for share previews');
 451→        }
 452→
 453→        const headerContentLength = Number(response.headers.get('content-length'));
 454→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
 455→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 456→        }
 457→
 458→        const arrayBuffer = await response.arrayBuffer();
 459→        const buffer = Buffer.from(arrayBuffer);
 460→
 461→        if (!buffer.length) {
 462→            throw new Error('upstream image is empty');
 463→        }
 464→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
 465→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 466→        }
 467→
 468→        return {
 469→            buffer,
 470→            contentType,
 471→            byteLength: buffer.length,
 472→            finalUrl,
 473→        };
 474→    } finally {
 475→        clearTimeout(timeout);
 476→    }
 477→};
