 531→app.use((req, res, next) => {
 532→    metricsState.requests += 1;
 533→    metricsState.inFlight += 1;
 534→
 535→    const startNs = process.hrtime.bigint();
 536→    let byteCount = 0;
 537→
 538→    const originalWrite = res.write.bind(res);
 539→    const originalEnd = res.end.bind(res);
 540→
 541→    res.write = (chunk, encoding, callback) => {
 542→        if (chunk) {
 543→            byteCount += Buffer.isBuffer(chunk)
 544→                ? chunk.length
 545→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 546→        }
 547→        return originalWrite(chunk, encoding, callback);
 548→    };
 549→
 550→    res.end = (chunk, encoding, callback) => {
 551→        if (chunk) {
 552→            byteCount += Buffer.isBuffer(chunk)
 553→                ? chunk.length
 554→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 555→        }
 556→        return originalEnd(chunk, encoding, callback);
 557→    };
 558→
 559→    res.on('finish', () => {
 560→        metricsState.inFlight = Math.max(0, metricsState.inFlight - 1);
 561→        metricsState.responses += 1;
 562→        metricsState.bytesSent += byteCount;
 563→
 564→        const statusBucket = classifyStatusBucket(res.statusCode);
 565→        metricsState.statusBuckets[statusBucket] += 1;
 566→
 567→        const durationMs = Number(process.hrtime.bigint() - startNs) / 1_000_000;
 568→        const routeTemplate = req.route?.path
 569→            ? `${req.baseUrl || ''}${req.route.path}`
 570→            : req.path;
 571→        const routeKey = `${req.method} ${canonicalizeMetricsPath(routeTemplate)}`;
 572→
 573→        let routeStat = metricsState.routeStats.get(routeKey);
 574→        if (!routeStat) {
 575→            if (metricsState.routeStats.size >= METRICS_ROUTE_LIMIT) {
 576→                return;
 577→            }
 578→
 579→            routeStat = {
 580→                count: 0,
 581→                totalDurationMs: 0,
 582→                maxDurationMs: 0,
 583→                bytesSent: 0,
 584→                statusBuckets: { '2xx': 0, '3xx': 0, '4xx': 0, '5xx': 0, other: 0 },
 585→            };
 586→            metricsState.routeStats.set(routeKey, routeStat);
 587→        }
 588→
 589→        routeStat.count += 1;
 590→        routeStat.totalDurationMs += durationMs;
 591→        routeStat.maxDurationMs = Math.max(routeStat.maxDurationMs, durationMs);
 592→        routeStat.bytesSent += byteCount;
 593→        routeStat.statusBuckets[statusBucket] += 1;
 594→    });
 595→
 596→    next();
 597→});
