 619→// ── Profile share route: composite OG image for social media ──
 620→app.get('/share/u/:username/image', async (req, res) => {
 621→    const { username } = req.params;
 622→    await ensureShareFonts();
 623→
 624→    try {
 625→        const result = await getUserByUsernameService(username);
 626→        const user = result?.userData?.[0];
 627→        if (!user) {
 628→            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 629→        }
 630→
 631→        const displayName = normalizeWhitespace(user.name) || username;
 632→        const handle = `@${normalizeWhitespace(user.username || username)}`;
 633→        const bio = toPreviewText(user.bio || '', 120);
 634→
 635→        // ── Fetch background image ──
 636→        let bgBuffer = null;
 637→        const bgStyle = user.background || {};
 638→        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
 639→            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
 640→            : null;
 641→        const bgImageUrl = bgImageMatch?.[1];
 642→
 643→        if (bgImageUrl) {
 644→            const bgEval = evaluateShareImageCandidate(bgImageUrl);
 645→            if (bgEval.ok && bgEval.resolvedUrl) {
 646→                try {
 647→                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
 648→                    bgBuffer = remote.buffer;
 649→                } catch { /* use fallback gradient */ }
 650→            }
 651→        }
 652→
 653→        // ── Base layer: background or dark gradient ──
 654→        let baseLayer;
 655→        if (bgBuffer) {
 656→            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
 657→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
 658→                .toBuffer();
 659→        } else {
 660→            // Use profile's solid background color if available, otherwise dark fallback
 661→            const solidColor = (typeof bgStyle.background === 'string' && /^#[0-9a-fA-F]{3,8}$/.test(bgStyle.background.trim()))
 662→                ? bgStyle.background.trim()
 663→                : null;
 664→            const gradientSvg = solidColor
 665→                ? `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 666→                    <rect width="100%" height="100%" fill="${solidColor}"/>
 667→                </svg>`
 668→                : `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 669→                    <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
 670→                        <stop offset="0%" stop-color="#1a1a2e"/>
 671→                        <stop offset="100%" stop-color="#16213e"/>
 672→                    </linearGradient></defs>
 673→                    <rect width="100%" height="100%" fill="url(#g)"/>
 674→                </svg>`;
 675→            baseLayer = await sharp(Buffer.from(gradientSvg))
 676→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT)
 677→                .png()
 678→                .toBuffer();
 679→        }
 680→
 681→        // ── Dark overlay for text readability ──
 682→        const overlaySvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 683→            <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
 684→        </svg>`;
 685→        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();
 686→
 687→        // ── Circular avatar ──
 688→        let avatarComposite = null;
 689→        const avatarSize = 180;
 690→        const avatarUrl = user.image_url;
 691→        if (avatarUrl) {
 692→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
 693→            if (avatarEval.ok && avatarEval.resolvedUrl) {
 694→                try {
 695→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
 696→                    const circleMask = Buffer.from(
 697→                        `<svg width="${avatarSize}" height="${avatarSize}">
 698→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
 699→                        </svg>`
 700→                    );
 701→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
 702→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
 703→                        .png()
 704→                        .toBuffer();
 705→                    const circularAvatar = await sharp(resizedAvatar)
 706→                        .composite([{ input: circleMask, blend: 'dest-in' }])
 707→                        .png()
 708→                        .toBuffer();
 709→                    avatarComposite = circularAvatar;
 710→                } catch { /* skip avatar */ }
 711→            }
 712→        }
 713→
 714→        // ── Compose all layers ──
 715→        const composites = [
 716→            { input: overlayBuffer, top: 0, left: 0 },
 717→        ];
 718→
 719→        if (avatarComposite) {
 720→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
 721→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
 722→        }
 723→
 724→        const finalImage = await sharp(baseLayer)
 725→            .composite(composites)
 726→            .jpeg({ quality: 82, mozjpeg: true })
 727→            .toBuffer();
 728→
 729→        res.set('Content-Type', 'image/jpeg');
 730→        res.set('Cache-Control', 'public, max-age=3600');
 731→        return res.send(finalImage);
 732→    } catch (err) {
 733→        console.error('profile share image route error:', err?.message || err);
 734→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 735→    }
 736→});
