 800→app.get('/share/post/:journalId/image', async (req, res) => {
 801→    const { journalId } = req.params;
 802→    await ensureShareFonts();
 803→    const debugMode = isShareImageDebugRequest(req);
 804→    const debugPayload = {
 805→        ok: false,
 806→        fallback: false,
 807→        journalId,
 808→        stage: 'start',
 809→        reason: '',
 810→        meta: {
 811→            imageCandidateSource: null,
 812→            imageCandidateRaw: null,
 813→            imageCandidateResolved: null,
 814→            upstreamFinalUrl: null,
 815→            upstreamContentType: null,
 816→            upstreamBytes: null,
 817→            outputBytes: null,
 818→        },
 819→    };
 820→
 821→    const fallbackWithReason = (reason) => {
 822→        debugPayload.ok = false;
 823→        debugPayload.fallback = true;
 824→        debugPayload.stage = 'fallback';
 825→        debugPayload.reason = reason;
 826→        if (debugMode) {
 827→            return sendShareImageDebug(res, debugPayload);
 828→        }
 829→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 830→    };
 831→
 832→    try {
 833→        const journal = await getShareJournal(journalId);
 834→        debugPayload.stage = 'journal_loaded';
 835→        if (!journal) {
 836→            return fallbackWithReason('journal_not_found');
 837→        }
 838→
 839→        const shareMeta = buildShareMetaFromJournal(journal);
 840→        debugPayload.stage = 'candidate_extracted';
 841→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
 842→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
 843→
 844→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
 845→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
 846→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
 847→            return fallbackWithReason(candidateEvaluation.reason);
 848→        }
 849→
 850→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
 851→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
 852→            return fallbackWithReason('candidate_is_default_fallback');
 853→        }
 854→
 855→        debugPayload.stage = 'fetching_upstream';
 856→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
 857→        debugPayload.stage = 'upstream_loaded';
 858→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
 859→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
 860→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
 861→
 862→        debugPayload.stage = 'converting_image';
 863→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
 864→        debugPayload.stage = 'converted_image';
 865→        debugPayload.ok = true;
 866→        debugPayload.reason = 'ok';
 867→        debugPayload.meta.outputBytes = ogImageBuffer.length;
 868→
 869→        if (debugMode) {
 870→            return sendShareImageDebug(res, debugPayload);
 871→        }
 872→
 873→        res.set('Content-Type', 'image/jpeg');
 874→        res.set('Cache-Control', 'public, max-age=3600');
 875→        return res.send(ogImageBuffer);
 876→    } catch (err) {
 877→        debugPayload.stage = 'error';
 878→        debugPayload.reason = err?.message || 'unknown_error';
 879→        console.error('share image route error:', err?.message || err);
 880→        return fallbackWithReason(debugPayload.reason);
 881→    }
 882→});
