              </Route>  
            </Route>   

            <Route path='/login' element={<LoginPage/>}/>
            <Route path='/signUp' element={<SignUp/>}/>
          </Routes>
        </Suspense>
      </BrowserRouter>
    </LexicalComposer>
    </>
  )
}

export default App

