                                            {icon.countBookmarks && icon.countBookmarks(journal.bookmark_count?.[0].count)}
                                            {icon.iconCount && icon.iconCount(journal?.views)}
                                        </div>
                                    ))
                                )}
                            </div>



                            <div className="reading-time-container">
                                <p className="reading-time-text">{CalculateText(wholeText)}</p>
                            </div>

                            <div className="user-post-settings">
                                <svg
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        setShareMenuPostId(shareMenuPostId === journal.id ? null : journal.id);
                                    }}
                                    xmlns="http://www.w3.org/2000/svg"
                                    height="24px"
                                    viewBox="0 0 24 24"
                                    width="24px"
                                    fill="currentColor"
                                >
                                    <path d="M18 16.08c-.76 0-1.44.3-1.96.77L8.91 12.7c.05-.23.09-.46.09-.7s-.04-.47-.09-.7l7.05-4.11c.54.5 1.25.81 2.04.81 1.66 0 3-1.34 3-3s-1.34-3-3-3-3 1.34-3 3c0 .24.04.47.09.7L8.04 9.81C7.5 9.31 6.79 9 6 9c-1.66 0-3 1.34-3 3s1.34 3 3 3c.79 0 1.5-.31 2.04-.81l7.12 4.16c-.05.21-.08.43-.08.65 0 1.61 1.31 2.92 2.92 2.92 1.61 0 2.92-1.31 2.92-2.92s-1.31-2.92-2.92-2.92z"/>
                                </svg>
                                {shareMenuPostId === journal.id && (
                                    <ShareMenu
                                        url={getShareUrl(journal.id)}
                                        title={journal.title || ''}
                                        onClose={() => setShareMenuPostId(null)}
                                    />
                                )}
                            </div>
                        </div>
                        {showBookmarkedMessage === journal.id && (
                            <div
                            className="bookmarked-content-message-container"
                            >
                                {bookmarkedMessage}

                            </div>
                        )}
                    </motion.div>
                )
            })}
            </>
            )}

            {!isSearchMode && (
                <div className="inview" ref={ref}>
                    <MoonLoader loading={activeIsFetchingNextPage} color="rgba(255, 255, 255, 0.64)" speedMultiplier={1} size={20}/>
                </div>
            )}
        </div>
       </AnimatePresence>

        {repostModalJournal && (
            <RepostModal
                journal={repostModalJournal}
                onClose={(result) => {
                    setRepostModalJournal(null);
                    if(result === 'success'){
                        setRepostToastMessage('Post was reposted');
                        setTimeout(() => setRepostToastMessage(''), 2500);
                    }
                }}
            />
        )}

        <AnimatePresence>
            {repostToastMessage && (
                <motion.div
                    className="repost-toast"
                    initial={{ opacity: 0, y: 8 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: 8 }}
                    transition={{ duration: 0.2 }}
                >
                    {repostToastMessage}
                </motion.div>
            )}
        </AnimatePresence>
        </>
    )
}

export default PostCards;

