 684→            <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
 685→        </svg>`;
 686→        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();
 687→
 688→        // ── Circular avatar ──
 689→        let avatarComposite = null;
 690→        const avatarSize = 180;
 691→        const avatarUrl = user.image_url;
 692→        if (avatarUrl) {
 693→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
 694→            if (avatarEval.ok && avatarEval.resolvedUrl) {
 695→                try {
 696→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
 697→                    const circleMask = Buffer.from(
 698→                        `<svg width="${avatarSize}" height="${avatarSize}">
 699→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
 700→                        </svg>`
 701→                    );
 702→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
 703→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
 704→                        .png()
 705→                        .toBuffer();
 706→                    const circularAvatar = await sharp(resizedAvatar)
 707→                        .composite([{ input: circleMask, blend: 'dest-in' }])
 708→                        .png()
 709→                        .toBuffer();
 710→                    avatarComposite = circularAvatar;
 711→                } catch { /* skip avatar */ }
 712→            }
 713→        }
 714→
 715→        // ── Compose all layers ──
 716→        const composites = [
 717→            { input: overlayBuffer, top: 0, left: 0 },
 718→        ];
 719→
 720→        if (avatarComposite) {
 721→            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
 722→            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
 723→        }
 724→
 725→        const finalImage = await sharp(baseLayer)
 726→            .composite(composites)
 727→            .jpeg({ quality: 82, mozjpeg: true })
 728→            .toBuffer();
 729→
 730→        res.set('Content-Type', 'image/jpeg');
 731→        res.set('Cache-Control', 'public, max-age=3600');
 732→        return res.send(finalImage);
 733→    } catch (err) {
 734→        console.error('profile share image route error:', err?.message || err);
 735→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 736→    }
