  1→import { useState } from 'react';
  2→import { useAuth } from '../../Context/useAuth.js';
  3→import supabase from '../../utils/supabaseClient.js';
  4→import { useNavigate, useSearchParams } from 'react-router-dom';
  5→import './SettingsPage.css';
  6→
  7→const SettingsPage = () => {
  8→    const { session } = useAuth();
  9→    const navigate = useNavigate();
 10→    const [searchParams, setSearchParams] = useSearchParams();
 11→    const isRecovery = searchParams.get('recovery') === 'true';
 12→
 13→    // Password state
 14→    const [currentPassword, setCurrentPassword] = useState('');
 15→    const [newPassword, setNewPassword] = useState('');
 16→    const [confirmPassword, setConfirmPassword] = useState('');
 17→    const [showCurrentPass, setShowCurrentPass] = useState(false);
 18→    const [showNewPass, setShowNewPass] = useState(false);
 19→    const [passwordLoading, setPasswordLoading] = useState(false);
 20→    const [passwordError, setPasswordError] = useState('');
 21→    const [passwordSuccess, setPasswordSuccess] = useState('');
 22→
 23→    // Email state
 24→    const [newEmail, setNewEmail] = useState('');
 25→    const [emailLoading, setEmailLoading] = useState(false);
 26→    const [emailError, setEmailError] = useState('');
 27→    const [emailSuccess, setEmailSuccess] = useState('');
 28→
 29→    const handleChangePassword = async (e) => {
 30→        e.preventDefault();
 31→        setPasswordError('');
 32→        setPasswordSuccess('');
 33→
 34→        if (newPassword.length < 6) {
 35→            return setPasswordError('New password must be at least 6 characters.');
 36→        }
 37→        if (newPassword !== confirmPassword) {
 38→            return setPasswordError('Passwords do not match.');
 39→        }
 40→
 41→        setPasswordLoading(true);
 42→        try {
 43→            if (!isRecovery) {
 44→                // Verify current password
 45→                const { error: signInError } = await supabase.auth.signInWithPassword({
 46→                    email: session.user.email,
 47→                    password: currentPassword,
 48→                });
 49→                if (signInError) {
 50→                    setPasswordLoading(false);
 51→                    return setPasswordError('Current password is incorrect.');
 52→                }
 53→            }
 54→
 55→            // Update to new password
 56→            const { error: updateError } = await supabase.auth.updateUser({
 57→                password: newPassword,
 58→            });
 59→            if (updateError) {
 60→                setPasswordLoading(false);
 61→                return setPasswordError(updateError.message);
 62→            }
 63→
 64→            setPasswordSuccess('Password updated successfully.');
 65→            setCurrentPassword('');
 66→            setNewPassword('');
 67→            setConfirmPassword('');
 68→
 69→            // Clear recovery param from URL
 70→            if (isRecovery) {
 71→                searchParams.delete('recovery');
 72→                setSearchParams(searchParams, { replace: true });
 73→            }
 74→        } catch (err) {
 75→            setPasswordError('Something went wrong. Please try again.');
 76→        } finally {
 77→            setPasswordLoading(false);
 78→        }
 79→    };
 80→
 81→    const handleChangeEmail = async (e) => {
 82→        e.preventDefault();
 83→        setEmailError('');
 84→        setEmailSuccess('');
 85→
 86→        if (!newEmail || !newEmail.includes('@')) {
 87→            return setEmailError('Please enter a valid email address.');
 88→        }
 89→        if (newEmail === session.user.email) {
 90→            return setEmailError('This is already your current email.');
 91→        }
 92→
 93→        setEmailLoading(true);
 94→        try {
 95→            const { error } = await supabase.auth.updateUser({
 96→                email: newEmail,
 97→            });
 98→            if (error) {
 99→                setEmailLoading(false);
100→                return setEmailError(error.message);
101→            }
102→
103→            setEmailSuccess('Confirmation email sent to ' + newEmail + '. Please check your inbox.');
104→            setNewEmail('');
105→        } catch (err) {
106→            setEmailError('Something went wrong. Please try again.');
107→        } finally {
108→            setEmailLoading(false);
109→        }
110→    };
111→
112→    if (!session) {
113→        return null;
114→    }
115→
116→    const isPasswordDisabled = (!isRecovery && !currentPassword) || !newPassword || !confirmPassword || passwordLoading;
117→    const isEmailDisabled = !newEmail || emailLoading;
118→
119→    return (
120→        <div className="settings-page">
121→            <div className="settings-header">
122→                <button className="settings-back-btn" onClick={() => navigate(-1)} aria-label="Go back">
123→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
124→                        <path d="M19 12H5"/>
125→                        <path d="M12 19l-7-7 7-7"/>
126→                    </svg>
127→                </button>
128→                <h1 className="settings-title">Settings</h1>
129→            </div>
130→
131→            {/* Change Password Section */}
132→            <section className="settings-section">
133→                <h2 className="settings-section-title">
134→                    {isRecovery ? 'Set New Password' : 'Change Password'}
135→                </h2>
136→                <form className="settings-form" onSubmit={handleChangePassword}>
137→                    {!isRecovery && (
138→                        <div className="settings-field">
139→                            <label htmlFor="current-password">Current Password</label>
140→                            <div className="input-with-action">
141→                                <input
142→                                    id="current-password"
143→                                    type={showCurrentPass ? 'text' : 'password'}
144→                                    value={currentPassword}
145→                                    onChange={(e) => setCurrentPassword(e.target.value)}
146→                                    placeholder="Enter current password"
147→                                    className="auth-input"
148→                                    autoComplete="current-password"
149→                                />
150→                                <button
151→                                    className="show-toggle"
152→                                    type="button"
153→                                    onClick={() => setShowCurrentPass((p) => !p)}
154→                                >
155→                                    {showCurrentPass ? 'Hide' : 'Show'}
156→                                </button>
157→                            </div>
158→                        </div>
159→                    )}
160→
161→                    <div className="settings-field">
162→                        <label htmlFor="new-password">New Password</label>
163→                        <div className="input-with-action">
164→                            <input
165→                                id="new-password"
166→                                type={showNewPass ? 'text' : 'password'}
167→                                value={newPassword}
168→                                onChange={(e) => setNewPassword(e.target.value)}
169→                                placeholder="At least 6 characters"
170→                                className="auth-input"
171→                                autoComplete="new-password"
172→                            />
173→                            <button
174→                                className="show-toggle"
175→                                type="button"
176→                                onClick={() => setShowNewPass((p) => !p)}
177→                            >
178→                                {showNewPass ? 'Hide' : 'Show'}
179→                            </button>
180→                        </div>
181→                    </div>
182→
183→                    <div className="settings-field">
184→                        <label htmlFor="confirm-password">Confirm New Password</label>
185→                        <input
186→                            id="confirm-password"
187→                            type="password"
188→                            value={confirmPassword}
